import UIKit
import Alamofire

class TradeViewController: UIViewController {
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var buyButton: UIButton!
    @IBOutlet weak var portfolioTableView: UITableView!

    let apiClient = APIClient()
    var userPortfolio: [Trade] = []

    override func viewDidLoad() {
        super.viewDidLoad()
        setupTableView()
    }

    @IBAction func buyAction(_ sender: UIButton) {
        guard let stockSymbol = stockSymbolTextField.text, let quantityString = quantityTextField.text,
              let quantity = Int(quantityString) else {
            return
        }
        
        apiClient.executeTrade(stockSymbol: stockSymbol, quantity: quantity) { result in
            switch result {
            case .success(let trade):
                self.userPortfolio.append(trade)
                self.portfolioTableView.reloadData()
            case .failure(let error):
                print("Error executing trade: \(error.localizedDescription)")
            }
        }
    }

    func setupTableView() {
        portfolioTableView.delegate = self
        portfolioTableView.dataSource = self
    }
}

extension TradeViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return userPortfolio.count
    }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TradeCell", for: indexPath)
        let trade = userPortfolio[indexPath.row]
        cell.textLabel?.text = "\(trade.stockSymbol): \(trade.quantity)"
        return cell
    }
}

class APIClient {
    func executeTrade(stockSymbol: String, quantity: Int, completion: @escaping (Result<Trade, Error>) -> Void) {
        // Simulate API call
        let trade = Trade(stockSymbol: stockSymbol, quantity: quantity)
        completion(.success(trade))
    }
}

struct Trade {
    let stockSymbol: String
    let quantity: Int
}